const f=n=>{if(n==null||n==="")return"0.00";const t=Number(n);return isNaN(t)?"0.00":t.toLocaleString("zh-CN",{minimumFractionDigits:2,maximumFractionDigits:2})};function l(n){if(!n||typeof n!="string")return null;const[t,e]=n.split("T");if(!t)return null;const[i,r,s]=t.split("-").map(Number);if(!i||!r||!s)return null;if(e){const[u,a]=e.split(":").map(Number);return{y:i,M:r,d:s,h:u||0,m:a||0}}return{y:i,M:r,d:s}}const c=n=>{const t=l(n);if(!t)return"-";const e=String(t.m).padStart(2,"0");return`${t.y}-${t.M}-${t.d}-${t.h}:${e}`},m=n=>{const t=l(n);return t?`${t.y}-${t.M}-${t.d}`:"-"},p=n=>{if(!n)return{line1:"-",line2:""};if(n.includes("—")){let e=0;for(let i=0;i<n.length;i++)if(n[i]==="-"&&(e++,e===3))return{line1:n.slice(0,i),line2:n.slice(i+1)};return{line1:n,line2:""}}const t=n.indexOf("-");return t===-1?{line1:n,line2:""}:{line1:n.slice(0,t),line2:n.slice(t+1)}};export{m as a,c as b,f,p as s};
